  writeOptionExplanations: z.boolean().optional(),
});

type CreateImproveQuestionsJobInput = {
  examId: string;
  questionIds: string[];
  concurrencyLimit?: number;
  writeExplanations?: boolean;
  writeOptionExplanations?: boolean;
};

export async function runImproveQuestionAgent(input: {
  ...
  webSearchApiKey?: string;
  writeOptionExplanations?: boolean;
})

function buildPrompt(questionId: string, writeOptionExplanations?: boolean): string {
  const lines = [
    `Improve question ${questionId}.`,
    'Always call get_question first.',
    ...
  ];
  if (writeOptionExplanations) {
    lines.splice(lines.length - 1, 0,
      'Also generate an explanation for each option explaining why it is correct or incorrect.'
    );
  }
  return lines.join('\n');
}
